import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        config_dict = {}
        
        for child in root:
            if child.tag not in config_dict:
                config_dict[child.tag] = child.text.strip() if child.text else None
        
        return config_dict
    except ET.ParseError as e:
        print(f"Error parsing XML: {e}")
        return None
    except FileNotFoundError:
        print(f"File not found: {file_path}")
        return None

# Example usage:
config = parse_xml_config('path_to_your_config_file.xml')
if config:
    print(config)